class ImageProcessingController < ApplicationController
  before_action :validate_params, only: [:convert]

  ALLOWED_FORMATS = %w[png jpg jpeg gif bmp tiff webp].freeze
  MAX_DIMENSION = 4096
  SIZE_PATTERN = /\A\d{1,4}x\d{1,4}\z/.freeze

  def convert
    uploaded_file = params[:image]

    unless uploaded_file.is_a?(ActionDispatch::Http::UploadedFile)
      return render json: { error: "No valid image file uploaded" }, status: :unprocessable_entity
    end

    format = sanitize_format(params[:format])
    size = sanitize_size(params[:size])

    unless format
      return render json: { error: "Invalid or unsupported format. Allowed: #{ALLOWED_FORMATS.join(', ')}" }, status: :unprocessable_entity
    end

    unless size
      return render json: { error: "Invalid size. Must be in WxH format (e.g., 800x600) with max dimension #{MAX_DIMENSION}" }, status: :unprocessable_entity
    end

    input_path = uploaded_file.tempfile.path

    unless valid_image?(input_path)
      return render json: { error: "Uploaded file is not a valid image" }, status: :unprocessable_entity
    end

    output_filename = "#{SecureRandom.uuid}.#{format}"
    output_path = Rails.root.join("tmp", output_filename).to_s

    success = convert_image(input_path, output_path, size)

    if success && File.exist?(output_path)
      send_file output_path,
                filename: "converted_image.#{format}",
                type: Mime::Type.lookup_by_extension(format)&.to_s || "application/octet-stream",
                disposition: "attachment"
    else
      render json: { error: "Image conversion failed" }, status: :internal_server_error
    end
  ensure
    File.delete(output_path) if output_path && File.exist?(output_path.to_s)
  end

