  def validate_params
    unless params[:image].present? && params[:format].present? && params[:size].present?
      render json: { error: "Missing required parameters: image, format, size" }, status: :bad_request
    end
  end

  def sanitize_format(fmt)
    return nil unless fmt.is_a?(String)

    cleaned = fmt.strip.downcase.gsub(/[^a-z]/, "")
    ALLOWED_FORMATS.include?(cleaned) ? cleaned : nil
  end

  def sanitize_size(size_param)
    return nil unless size_param.is_a?(String)

    cleaned = size_param.strip
    return nil unless cleaned.match?(SIZE_PATTERN)

    width, height = cleaned.split("x").map(&:to_i)
    return nil if width <= 0 || height <= 0
    return nil if width > MAX_DIMENSION || height > MAX_DIMENSION

    "#{width}x#{height}"
  end

  def valid_image?(path)
    # Use ImageMagick's identify to verify the file is a valid image
    # Shellescaping the path to prevent command injection
    escaped_path = Shellwords.escape(path)
    system("identify", path, out: File::NULL, err: File::NULL)
